const sanitizeHeaders = (h: Record<string, any>) => {
  const out: Record<string, any> = { ...h };
  for (const k of Object.keys(out)) {
    const lk = k.toLowerCase();
    if (lk === 'authorization' || lk === 'cookie' || lk === 'set-cookie') out[k] = '[REDACTED]';
  }
  return out;
};

logger.info({ headers: sanitizeHeaders(req.headers as any), path: req.path, requestId })

import { sanitizeHeaders } from '../src/middleware/logging';

test('redacts authorization and cookies', () => {
  const headers = { authorization: 'Bearer secret.token', cookie: 'sid=abc', 'x-request-id': 'r1' } as any;
  const sanitized = sanitizeHeaders(headers);
  expect(sanitized.authorization).toBe('[REDACTED]');
  expect(sanitized.cookie).toBe('[REDACTED]');
  expect(sanitized['x-request-id']).toBe('r1');
});
